,cAAA;AxBylGF;AwBxlGE;EAFF;IAGI,cAAA;ExB2lGF;AACF","file":"style.css","sourcesContent":["/*=== MEDIA QUERY ===*/\n@mixin mobile-xs{\n  @media(max-width:400px){\n    @content;\n  }\n}\n@mixin mobile{\n  @media(max-width:480px){\n    @content;\n  }\n}\n@mixin tablet-xs{\n  @media(max-width:640px){\n    @content;\n  }\n}@mixin tablet{\n  @media(max-width:768px){\n    @content;\n  }\n}\n@mixin desktop{\n  @media(max-width:992px){\n    @content;\n  }\n}\n@mixin large-desktop{\n  @media(max-width:1200px){\n    @content;\n  }\n}\n","/*-----------------------------\n CSS INDEXING\n* --------------------------------------\n* 01.GLOBAL CSS STYLE\n* 02.TYPOGRAPHY CSS STYLE\n* 03.BUTTONS STYLE\n* 04.HOMEPAGE CSS STYLE\n    -LOGO CSS\n    -MENU CSS\n    -BACKGROUND\n* 05.FEATURES CSS STYLE\n* 06.SERVICE CSS STYLE\n* 07.ABOUT CSS STYLE\n* 08.PRICING CSS STYLE\n* 09.TESTIMONIAL STYLE\n* 10.LATEST BLOG CSS STYLE\n* 11.CONTACT CSS STYLE\n* 12.FOOTER CSS STYLE\n* ----------------------------------------\n*/\n\n// Fonts\n@import url(\"https://fonts.googleapis.com/css2?family=Plus Jakarta Sans:wght@400;500;600;700;800;900&display=swap\");\n\nhtml {\n  line-height: 1.15;\n  -webkit-text-size-adjust: 100%;\n  -ms-text-size-adjust: 100%;\n  // -ms-overflow-style: scrollbar;\n  -webkit-tap-highlight-color: rgba(0, 0, 0, 0);\n  font-family: \"Plus Jakarta Sans\", sans-serif !important;\n  overflow-x: hidden;\n  box-sizing: border-box;\n}\n\nbody {\n  font-family: $secondary-font;\n  font-size: 15px;\n  line-height: 1.75;\n  margin: 0;\n  text-align: left;\n  background-color: #fff;\n  font-weight: 400;\n  color: $black-light;\n}\n\n/*--------------------\n TYPOGRAPHY\n-----------------*/\n\n.h1,\n.h2,\n.h3,\n.h4,\n.h5,\n.h6,\nh1,\nh2,\nh3,\nh4,\nh5,\nh6 {\n  font-family: $primary-font;\n  font-weight: 700;\n  line-height: 1.35;\n  margin-bottom: 0.5rem;\n  color: $black;\n}\n\n.h1,\nh1 {\n  font-size: 2.125rem;\n  line-height: 40px;\n}\n\n.h2,\nh2 {\n  font-size: 1.625rem;\n}\n\n.h3,\nh3 {\n  font-size: 1.375rem;\n}\n\n.h4,\nh4 {\n  font-size: 1.125rem;\n}\n\n.h5,\nh5 {\n  font-size: 0.9375rem;\n}\n\n.h6,\nh6 {\n  font-size: 0.75rem;\n}\n\n.lead {\n  font-size: 1.0625rem;\n  font-weight: 300;\n}\n\n.font-weight-500 {\n  font-weight: 500 !important;\n}\n\n.section-title {\n  font-family: $secondary-font;\n  font-size: 43px;\n  font-weight: 700;\n  text-transform: capitalize;\n  margin-bottom: 15px;\n}\n\n.bg-grey {\n  background: $secondary-color;\n}\n\n.text-primary {\n  color: $primary-color !important;\n  background: $secondary-color;\n}\n","/*=== MEDIA QUERY ===*/\n/*-----------------------------\n CSS INDEXING\n* --------------------------------------\n* 01.GLOBAL CSS STYLE\n* 02.TYPOGRAPHY CSS STYLE\n* 03.BUTTONS STYLE\n* 04.HOMEPAGE CSS STYLE\n    -LOGO CSS\n    -MENU CSS\n    -BACKGROUND\n* 05.FEATURES CSS STYLE\n* 06.SERVICE CSS STYLE\n* 07.ABOUT CSS STYLE\n* 08.PRICING CSS STYLE\n* 09.TESTIMONIAL STYLE\n* 10.LATEST BLOG CSS STYLE\n* 11.CONTACT CSS STYLE\n* 12.FOOTER CSS STYLE\n* ----------------------------------------\n*/\n@import url(\"https://fonts.googleapis.com/css2?family=Plus Jakarta Sans:wght@400;500;600;700;800;900&display=swap\");\nhtml {\n  line-height: 1.15;\n  -webkit-text-size-adjust: 100%;\n  -ms-text-size-adjust: 100%;\n  -webkit-tap-highlight-color: rgba(0, 0, 0, 0);\n  font-family: \"Plus Jakarta Sans\", sans-serif !important;\n  overflow-x: hidden;\n  box-sizing: border-box;\n}\n\nbody {\n  font-family: \"Plus Jakarta Sans\", sans-serif;\n  font-size: 15px;\n  line-height: 1.75;\n  margin: 0;\n  text-align: left;\n  background-color: #fff;\n  font-weight: 400;\n  color: #6c757d;\n}\n\n/*--------------------\n TYPOGRAPHY\n-----------------*/\n.h1,\n.h2,\n.h3,\n.h4,\n.h5,\n.h6,\nh1,\nh2,\nh3,\nh4,\nh5,\nh6 {\n  font-family: \"Plus Jakarta Sans\", sans-serif;\n  font-weight: 700;\n  line-height: 1.35;\n  margin-bottom: 0.5rem;\n  color: #212529;\n}\n\n.h1,\nh1 {\n  font-size: 2.125rem;\n  line-height: 40px;\n}\n\n.h2,\nh2 {\n  font-size: 1.625rem;\n}\n\n.h3,\nh3 {\n  font-size: 1.375rem;\n}\n\n.h4,\nh4 {\n  font-size: 1.125rem;\n}\n\n.h5,\nh5 {\n  font-size: 0.9375rem;\n}\n\n.h6,\nh6 {\n  font-size: 0.75rem;\n}\n\n.lead {\n  font-size: 1.0625rem;\n  font-weight: 300;\n}\n\n.font-weight-500 {\n  font-weight: 500 !important;\n}\n\n.section-title {\n  font-family: \"Plus Jakarta Sans\", sans-serif;\n  font-size: 43px;\n  font-weight: 700;\n  text-transform: capitalize;\n  margin-bottom: 15px;\n}\n\n.bg-grey {\n  background: #F4F7FC;\n}\n\n.text-primary {\n  color: #21c87a !important;\n  background: #F4F7FC;\n}\n\n/*--------------------\nCommon Styles\n-----------------*/\nimg {\n  vertical-align: middle;\n  border-style: none;\n}\n\n.img-thumbnail {\n  padding: 0.25rem;\n  border: 1px solid #dee2e6;\n  background-color: #fff;\n}\n\n.section {\n  position: relative;\n  padding: 8.125rem 0;\n}\n\n@media (min-width: 768px) {\n  .section {\n    padding: 4.5rem 0;\n  }\n}\n.section-top {\n  padding-top: 8.125rem;\n}\n\n.section-bottom {\n  padding-bottom: 8.125rem;\n}\n\n@media (min-width: 768px) {\n  .section-top {\n    padding-top: 10.3125rem;\n  }\n}\n.bg-grey {\n  background: #f4f7fc;\n}\n\n/*-------------------\n  BUTTONS STYLE\n----------------=----*/\n.btn {\n  font-size: 0.6875rem;\n  font-weight: 700;\n  position: relative;\n  text-transform: uppercase;\n  padding: 1rem 2.4rem;\n  border: 0.1rem solid transparent;\n  transition: all 0.2s ease-in-out;\n  letter-spacing: 0.5px;\n}\n\n.btn-primary-border {\n  border-radius: 8px;\n  border: 3px solid #30ab89;\n  font-size: 0.875rem;\n}\n\n.btn-circle {\n  display: inline-flex;\n  width: 4.20313rem !important;\n  height: 4.20313rem !important;\n  padding: 0 !important;\n  border-radius: 50%;\n  align-items: center;\n  justify-content: center;\n}\n\n.btn-outline-dark {\n  border: 1px solid #222;\n}\n\n.btn-white {\n  background: #fff;\n  color: #212529;\n}\n\n.btn-trans-white {\n  border: 1px solid #fff;\n  color: #fff;\n}\n.btn-trans-white:hover {\n  color: #fff;\n  opacity: 0.5;\n}\n\n.btn-outline-dark:hover {\n  background: #222 !important;\n  color: #fff !important;\n}\n\n.btn.btn-link {\n  color: #212529;\n}\n\n.btn:focus {\n  box-shadow: none !important;\n}\n\n.btn-circled {\n  border-radius: 75px;\n}\n\n.bg-primary,\n.btn-primary,\n.btn-white:hover {\n  background: #21c87a !important;\n  border-color: #21c87a !important;\n  color: #fff;\n}\n\n.bg-dark,\n.btn-primary:hover {\n  background: #232323 !important;\n  border-color: #232323 !important;\n  color: #fff;\n}\n\n.shadow-sm-2 {\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n\n/*------------------------\n BACKGROUND\n----------------------------*/\n.bg-cover {\n  background-repeat: no-repeat;\n  background-position: 50%;\n  background-size: cover;\n}\n\n.bg-cover,\n.bg-overlay,\n.bg-overlay:before {\n  position: absolute;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n}\n\n.bg-overlay:before {\n  content: \"\";\n  opacity: 0.55;\n  background-color: #212529;\n}\n\n.box-shadow {\n  box-shadow: 0 25px 100px -5px rgba(0, 0, 0, 0.15);\n}\n\n.mt50 {\n  margin-top: 80px;\n}\n\n.mt30 {\n  margin-top: 30px;\n}\n\n.mb-30 {\n  margin-bottom: 30px;\n}\n\n.bg-primary {\n  background: #21c87a !important;\n}\n\na {\n  color: #21c87a;\n  transition: 0.3s;\n}\n\na:hover,\na:focus {\n  outline: none;\n  text-decoration: none;\n  color: #1a9c5f;\n}\n\n.disabled-text {\n  color: rgba(255, 255, 255, 0.8) !important;\n  cursor: not-allowed;\n}\n\n.logo {\n  width: 100%;\n  height: 100%;\n}\n\n.luminous-blend {\n  mix-blend-mode: luminosity !important;\n}\n\n.bg-home {\n  background: url(\"/images/bg/background.png\");\n  background-position: center;\n  background-size: cover;\n  padding-top: 7rem;\n}\n@media (max-width: 991px) {\n  .bg-home {\n    padding-top: 2rem;\n  }\n}\n\n.seed-section {\n  padding: 92px 0;\n}\n@media (max-width: 991px) {\n  .seed-section {\n    padding: 48px 0;\n  }\n}\n\n/*----------------------\n HEADER STYLE\n-----------------------*/\n.header-socials {\n  line-height: 22px;\n  margin-bottom: 0px;\n}\n.header-socials li {\n  padding: 8px;\n}\n.header-socials li a {\n  color: #21c87a;\n}\n\n/*-----------------\n LOGO BAR\n-------------------*/\n.logo-bar {\n  padding: 2px 0px 60px;\n}\n\n.top-info-block {\n  margin-right: 30px;\n}\n.top-info-block h5,\n.top-info-block p {\n  margin-bottom: 0px;\n}\n\n.icon-block {\n  margin-right: 20px;\n  color: #21c87a;\n  font-size: 40px;\n  line-height: 20px;\n  font-weight: 400;\n}\n\n.top-info-block:last-child {\n  margin-right: 0px;\n}\n\n.header-bar {\n  overflow: visible;\n  position: relative;\n  padding-bottom: 30px;\n}\n\n.main-navigation {\n  margin-top: -40px;\n}\n\n/*-----------------------\n HOME-3\n---------------------------*/\n.header-white {\n  background: #101010;\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  border-radius: 0px;\n}\n\n@media (max-width: 992px) {\n  .trans-navigation {\n    background: #101010;\n    -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n    border-radius: 0px;\n  }\n}\n\n.trans-navigation .navbar-brand h4,\n.site-navigation .navbar-brand h4,\n.site-navigation .navbar-brand h3,\n.trans-navigation .navbar-brand h3 {\n  color: #fff;\n}\n\n.banner-content.style-2 {\n  padding-top: 200px;\n}\n\n.trans-navigation .navbar-brand {\n  padding-top: 13px;\n}\n\n.site-navigation.header-white {\n  border-bottom: 1px solid transparent;\n}\n\n.site-navigation .navbar-brand {\n  padding-top: 13px;\n  margin-right: 20px;\n}\n\n.banner-content2 {\n  padding: 200px 0px;\n}\n.banner-content2 .display-4 {\n  color: #fff;\n  font-weight: 600;\n}\n.banner-content2 p.lead {\n  color: #fff;\n}\n\n/* =========================\nPRELOADER\n=======================*/\n#page-loader {\n  background: #fff;\n  height: 100%;\n  width: 100%;\n  position: fixed;\n  z-index: 1050;\n}\n\n.loader-icon {\n  background: none repeat scroll 0 0 #fff;\n  border-bottom: 3px solid rgba(19, 19, 19, 0.1) !important;\n  border-left: 3px solid rgba(19, 19, 19, 0.1) !important;\n  border-radius: 100px;\n  -moz-border-radius: 100px;\n  -webkit-border-radius: 100px;\n  -o-border-radius: 100px;\n  -ms-border-radius: 100px;\n  border-right: 3px solid #1453F2 !important;\n  border-top: 3px solid rgba(19, 19, 19, 0.1) !important;\n  height: 50px;\n  left: 50%;\n  margin: -20px 0 0 -20px;\n  position: absolute;\n  text-align: center;\n  top: 50%;\n  width: 50px;\n  -webkit-transform: translate(-50%, -50%);\n  -ms-transform: translate(-50%, -50%);\n  transform: translate(-50%, -50%);\n}\n\n.colored-border {\n  border-color: #fff;\n}\n\n.fa-spin {\n  -webkit-animation: fa-spin 1s infinite linear;\n  animation: fa-spin 1s infinite linear;\n}\n\n@-webkit-keyframes fa-spin {\n  0% {\n    -webkit-transform: rotate(0deg);\n    transform: rotate(0deg);\n  }\n  100% {\n    -webkit-transform: rotate(359deg);\n    transform: rotate(359deg);\n  }\n}\n@keyframes fa-spin {\n  0% {\n    -webkit-transform: rotate(0deg);\n    transform: rotate(0deg);\n  }\n  100% {\n    -webkit-transform: rotate(359deg);\n    transform: rotate(359deg);\n  }\n}\n/*--------------------------\nPAGE BANNER\n--------------------------*/\n.page-banner-area {\n  padding: 180px 0px;\n}\n\n.page-contact {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/p-6.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-service {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/service.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-about {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/about.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-pricing {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/img2.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-project {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/p-4.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-banner-content h1 {\n  color: #fff;\n}\n\n.page-banner-content p {\n  color: #eee;\n}\n\n.form-control {\n  border-radius: 0px;\n  height: 45px;\n}\n\n/*-------------------\n   MENU\n----------------------*/\n.navbar-toggler-icon {\n  display: inline-block;\n  width: 1.5em;\n  height: 1.5em;\n  content: \"\";\n  vertical-align: middle;\n  background: no-repeat 50%;\n  background-size: 100% 100%;\n}\n\n.navbar-dark .navbar-toggler {\n  color: #fff;\n  border-color: rgba(255, 255, 255, 0.1);\n  padding: 10px 12px;\n}\n.navbar-dark .navbar-toggler:focus {\n  outline: 0;\n}\n\n.main-nav {\n  margin-bottom: -45px;\n  z-index: 999;\n}\n\n.navbar-nav .nav-link {\n  padding-right: 1rem !important;\n  padding-left: 1rem !important;\n  transition: 0.3s;\n}\n\n.navbar-dark .navbar-nav .nav-link {\n  color: #fff;\n  font-weight: 500;\n  letter-spacing: 0.5px;\n}\n\n.rounded-radius {\n  border-radius: 5px;\n}\n\n.navbar {\n  position: relative;\n  padding: 1rem 1rem;\n}\n.navbar:before {\n  position: absolute;\n  z-index: -1;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n  content: \"\";\n  transition: opacity 0.15s linear;\n  opacity: 0;\n  border-bottom: 1px solid rgba(0, 0, 0, 0.1);\n  background-color: #fff;\n}\n\n.dropdown-toggle::after {\n  margin-left: 0.255em;\n  vertical-align: 1px;\n  content: \"\\f078\";\n  border: 0;\n  font-family: \"Font Awesome 5 Free\";\n  font-size: 12px;\n}\n\n.fixed-top {\n  position: fixed;\n  z-index: 1030;\n  right: 0;\n  left: 0;\n}\n\n.navbar-dark {\n  color: #fff;\n}\n\n.navbar-light {\n  color: #212529;\n}\n.navbar-light:before {\n  opacity: 1;\n}\n\n.navbar .nav-item-divider {\n  display: none;\n}\n.navbar .nav-item-divider .nav-link {\n  opacity: 0.25;\n}\n\n.header-bar.fixed-header .main-navigation {\n  position: fixed;\n  left: 0;\n  top: 0;\n  width: 100%;\n  background: #101010;\n  border-color: transparent;\n}\n\n.primary-btn {\n  padding: 0.5rem 1.25rem;\n  border-radius: 2rem;\n  background-color: #30ab89;\n  font-weight: 500;\n  color: #fff;\n  font-size: 1rem;\n}\n.primary-btn .nav-link {\n  padding: 0;\n  font-weight: 500;\n}\n\n.primary-btn:hover, .primary-btn:visited {\n  color: #fff;\n}\n\n/*-------------------\n  DROPDOWN MENU\n----------------------*/\n.has-dropdown .dropdown-menu {\n  border: none;\n  box-shadow: 0 0 25px 0 rgba(0, 0, 0, 0.08);\n  padding: 0;\n  margin: 0;\n}\n@media (max-width: 992px) {\n  .has-dropdown .dropdown-menu {\n    text-align: center;\n    float: left !important;\n    width: 100%;\n    margin: 0;\n  }\n}\n.has-dropdown .dropdown-menu a {\n  font-weight: normal;\n  color: #808080;\n  padding: 10px 20px;\n  -webkit-transition: all 0.3s ease;\n  -moz-transition: all 0.3s ease;\n  -ms-transition: all 0.3s ease;\n  -o-transition: all 0.3s ease;\n  transition: all 0.3s ease;\n  border-bottom: 1px solid #eee;\n  border-radius: 4px;\n}\n.has-dropdown .dropdown-menu a:focus, .has-dropdown .dropdown-menu a:hover {\n  background: #21c87a;\n  color: #fff;\n}\n\n.dropleft .dropdown-menu,\n.dropright .dropdown-menu {\n  margin: 0;\n}\n\n.dropleft .dropdown-toggle::before,\n.dropright .dropdown-toggle::after {\n  font-weight: bold;\n  font-family: \"Font Awesome 5 Free\";\n  border: 0;\n  font-size: 10px;\n  vertical-align: 1px;\n}\n\n.dropleft .dropdown-toggle::before {\n  content: \"\\f053\";\n  margin-right: 7px;\n}\n\n.dropright .dropdown-toggle::after {\n  content: \"\\f054\";\n  margin-left: 7px;\n}\n\n.dropdown-item {\n  padding: 0.6rem 1.4rem;\n  text-transform: uppercase;\n  font-size: 12px;\n  font-weight: 700;\n}\n\n.dropdown-submenu:hover > .dropdown-item,\n.dropdown-item:hover {\n  background: #101010;\n  color: #fff !important;\n}\n\n.dropdown-item.active {\n  text-decoration: underline;\n  background-color: transparent;\n  color: inherit;\n}\n\n.dropdown-submenu.active > .dropdown-toggle {\n  text-decoration: underline;\n  color: inherit;\n}\n\nul.dropdown-menu li {\n  padding-left: 0px !important;\n}\n\n@media (min-width: 992px) {\n  .dropdown-menu {\n    transition: all 0.2s ease-in, visibility 0s linear 0.2s, transform 0.2s linear;\n    display: block;\n    visibility: hidden;\n    opacity: 0;\n    min-width: 200px;\n    transform: translateY(15px);\n  }\n  .dropdown:hover > .dropdown-menu {\n    visibility: visible;\n    transition: all 0.35s ease 0s;\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n.pt-60px {\n  padding-top: 60px !important;\n}\n\n@media (max-width: 992px) {\n  .position-md-sticky {\n    position: sticky !important;\n  }\n}\n/*----------------------\n BANNER STYLE\n-----------------------*/\n.py-7 {\n  padding: 7.5rem 0;\n}\n\n.py-4 {\n  padding: 4.5rem 0;\n}\n\n.py-8 {\n  padding: 8.5rem 0;\n}\n\n.main-banner h5 {\n  margin-bottom: 20px;\n}\n.main-banner h1.display-4 {\n  line-height: 65px;\n}\n\n.main-banner p.lead,\n.banner-content p.lead {\n  margin-bottom: 2.5rem !important;\n}\n\n/*-------------------------\n HOME -2\n-----------------------------*/\n#banner {\n  position: relative;\n  background: url(\"/images/bg/banner_bg.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.banner-content {\n  padding: 150px 0px;\n  padding-right: 30px;\n}\n.banner-content p {\n  color: #eee;\n  padding-right: 80px;\n  margin-bottom: 30px !important;\n}\n.banner-content .display-4 {\n  color: #fff;\n  font-weight: 600;\n}\n\n#banner .overlay {\n  opacity: 0.7;\n}\n\n.banner-contact-form {\n  padding: 45px 40px;\n  margin-top: 30px;\n}\n.banner-contact-form .form-control {\n  border-radius: 0px;\n  height: 45px;\n}\n.banner-contact-form textarea.form-control {\n  height: auto;\n}\n\n.transform-y-10 {\n  transform: tra