t h1 {\n  margin-bottom: 20px;\n  margin-top: 15px;\n}\n\n.service-icon {\n  margin-right: 20px;\n  color: #fff;\n  font-size: 25px;\n  width: 50px;\n  height: 50px;\n  background: #A5EBD7;\n  text-align: center;\n  border-radius: 50%;\n  padding-top: 5px;\n}\n\n.service-block {\n  margin-bottom: 50px;\n}\n\n/*----------------------\n WEB SERVICES\n-----------------------*/\n#services-2 {\n  position: relative;\n  padding: 20px;\n  -webkit-background-size: cover;\n  background-size: cover;\n  background-color: #FAFAFA;\n  color: #2C2C2C;\n}\n\n.service-blocks {\n  display: grid;\n  grid-template-columns: 1fr 1fr 1fr;\n  gap: 30px;\n}\n@media (max-width: 1154px) {\n  .service-blocks {\n    grid-template-columns: 1fr 1fr;\n  }\n}\n@media (max-width: 800px) {\n  .service-blocks {\n    grid-template-columns: 1fr;\n  }\n}\n\n.web-service-block {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 1.5rem;\n  transition: 0.3s;\n  border-radius: 5px;\n  cursor: pointer;\n}\n.web-service-block .image-container {\n  height: 4rem;\n}\n.web-service-block .image-container img {\n  height: 100%;\n  filter: brightness(1) invert(1);\n}\n.web-service-block h3 {\n  font-size: 25px;\n  margin: 0;\n  transition: 0.3s;\n  color: #2C2C2C;\n}\n.web-service-block p {\n  font-size: 15px;\n  font-weight: 400;\n  transition: 0.3s;\n  color: #2C2C2C;\n  line-height: 1.5;\n}\n.web-service-block a {\n  color: #30AB89 !important;\n  font-size: 18px;\n  font-weight: 700;\n  cursor: pointer;\n  margin-top: auto;\n}\n\n.service-img {\n  margin-bottom: -200px !important;\n  border: 10px solid #fff;\n  margin: auto;\n}\n\n/*----------------------\n PRoject\n-----------------------*/\n#projects-wrap {\n  position: relative;\n  background: url(\"../images/bg/banner_bg.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n#projects-wrap p.lead {\n  color: #a9a9a9 !important;\n}\n\n.overlay {\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 100%;\n  