) {\n  .workflow-header h6 {\n  color: var(--text-color, #2C2C2C);\n  text-align: center;\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 500;\n  line-height: normal;\n  }\n}\n.greenHorizontalLine {\n  width: 100%;\n}\n.workFlow-heading {\n  margin: 4rem auto;\n}\n.workFlow-heading h3 {\n  text-align: center;\n  font-size: 32px;\n  line-height: 40.22px;\n  @media (max-width: 1154px) {\n    font-size: 25px;\n  }\n  font-style: normal;\n  font-weight: 700;\n}\n.workFlow-heading h3 span {\n  color: #187f5f;\n  font-weight: 700;\n}\n@media screen and (max-width: 1108px) {\n  .workFlow-heading h3 {\n    font-size: 45px;\n  }\n}\n@media screen and (max-width: 1102px) {\n  .workFlow-heading h3 {\n    font-size: 40px;\n  }\n}\n@media screen and (max-width: 1102px) {\n  .workFlow-heading h3 {\n    font-size: 35px;\n  }\n}\n@media screen and (max-width: 804px) {\n  .greenHorizontalLine {\n    display: none;\n  }\n}\n.workFlow-body {\n  // background: rgba(255, 255, 255, 0.5) url(../../images/workFlow/Bg\\ logo.png)\n  //   no-repeat;\n  background-position: center;\n  position: relative;\n}\n.workFlow-body .workflowContainer {\n  //   background: $green-border;\n  border-radius: 10px;\n  padding-top: 6px;\n  //   padding: 6px;\n  box-sizing: border-box;\n  border-radius: 10px;\n  //   padding: 10px;\n  font-size: 19px;\n  box-sizing: border-box;\n  //   margin-top: 1rem;\n  color: black;\n  font-weight: 400px;\n\n  max-width: 405px;\n}\n.workFlow-body h3 {\n  color: var(--heading-color, #202020);\ntext-align: center;\nfont-family: Plus Jakarta Sans;\nfont-size: 24px;\nfont-style: normal;\nfont-weight: 600;\nline-height: 35px; /* 145.833% */\nmargin: 0;\ntext-align: end;\nmax-width: 405px;\n\n}\n.completeCard {\n  display: flex;\n  justify-content: space-between;\n  align-items: flex-start;\n  gap: 4rem;\n}\n.allCards {\n  position: absolute;\n  top: 0;\n  left: 50%;\n  display: flex;\n  flex-direction: column;\n  justify-content: space-evenly;\n  transform: translate(-72%, 0);\n  // width: 100%;\n  height: 100%;\n}\n.imageContainer {\n  transform: translateY(-15px);\n  width: 143px;\n  height: 83px;\n}\n.evencompleteCard {\n  display: flex;\n  justify-content: space-between;\n  align-items: flex-start;\n  gap: 2rem;\n  transform: translateX(45%);\n}\n.evencompleteCard h3,\n.evencompleteCard div {\n  text-align: left;\n}\n@media screen and (max-width: 1300px) {\n  .workFlow-body .workflowContainer {\n    width: 550px;\n  }\n}\n@media screen and (max-width: 1200px) {\n  .workFlow-body .workflowContainer {\n    width: 500px;\n  }\n  .workFlow-body h3 {\n    font-size: 25px;\n  }\n  .allCards {\n    transform: translate(-70%, 0);\n  }\n  .evencompleteCard {\n    transform: translateX(40%);\n  }\n}\n@media screen and (max-width: 1070px) {\n  .workFlow-body h3 {\n    font-size: 19px;\n  }\n  .workFlow-body .workflowContainer {\n    font-size: 16px;\n  }\n  .workFlow-body .workflowContainer {\n    width: 400px;\n  }\n  .allCards {\n    transform: translate(-78%, 0);\n  }\n  .evencompleteCard {\n    transform: translateX(55%);\n  }\n  .imageContainer {\n    width: 110px;\n  }\n}\n@media screen and (max-width: 850px) {\n  .workflowCenterStick {\n    width: 18px;\n  }\n  .workFlow-body h3 {\n    font-size: 16px;\n  }\n  .workFlow-body .workflowContainer {\n    width: 250px;\n    font-size: 12px;\n    margin-top: 0.5rem;\n  }\n  .imageContainer {\n    width: auto;\n    height: auto;\n    transform: translateY(0);\n  }\n  .imageContainer > img {\n    width: 90px;\n  }\n  .completeCard {\n    justify-content: center;\n    gap: 2rem;\n  }\n  .allCards {\n    transform: translate(-70%, 0);\n  }\n  .evencompleteCard {\n    transform: translateX(40%);\n    justify-content: center;\n    // gap: .5rem;\n  }\n  .evencompleteCard > .imageContainer > img {\n    text-align: right;\n  }\n}\n@media screen and (max-width: 560px) {\n  .workFlow-body .workflowContainer {\n    width: 150px;\n    font-size: 9px;\n  }\n  .allCards {\n    transform: translate(-65%, 0);\n  }\n  .imageContainer > img {\n    width: 70px;\n  }\n  .workFlow-body h3 {\n    width: 150px;\n    font-size: 12px;\n    line-height: 20px;\n  }\n  .evencompleteCard {\n    transform: translateX(34%);\n  }\n}\n",".service-content h1 {\n  color: #1b1b1b;\n  // font-family: Poppins;\n  font-size: 32px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: 50px; /* 142.857% */\n}\n.service-content h1 span {\n  color: #30AB89;\n  font-weight: 700;\n}\n.service-content p {\n  color: #474747;\n  text-align: justify;\n  // font-family: Poppins;\n  font-size: 18px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: 25px; /* 119.048% */\n}\n.service-img {\n  position: relative !important;\n  z-index: 1 !important;\n  border: 0px;\n}\n.service-img img {\n  border-radius: 20px;\n}\n#service .service-img::before {\n  position: absolute;\n  z-index: -1;\n  width: 100%;\n  max-width: 404px;\n  height: 100%;\n  content: \"\";\n  top: 0;\n  left: 0;\n  background: $image-background-banner;\n  transform: translate(-20px, 20px);\n  border-radius: 20px;\n}\n.service-wrap .service-icon {\n  background: #A5EBD7;\n}\n.service-wrap .contact-para {\n  color: #118666;\n  font-family: \"Plus Jakarta Sans\";\n  font-size: 17px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: 25px;\n}\n\n@media screen and (max-width: 991px) {\n  .service-content h1 {\n    font-size: 24px;\n    line-height: 28px;\n  }\n  .service-content p {\n    font-size: 18px;\n  }\n  .service-img {\n    position: static;\n    text-align: center;\n    margin-bottom: 0 !important;\n  }\n}\n.bg-grey {\n  // background: url(../../images/about/image\\ 5.png);\n  background-size: contain;\n  background-repeat: repeat;\n}\n// @media screen and (max-width: 420px) {\n//   .service-wrap .contact-para {\n//     text-align: center;\n//   }\n//   .service-wrap .contact-para a {\n//     display: block;\n//     margin-top: 1rem !important;\n//     margin: auto;\n//   }\n// }\n@media screen and (max-width: 500px) {\n  .service-wrap .contact-para {\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    gap: 1rem;\n  }\n}\n",".map {\n  background: #101010;\n}\n.map .earn-trust {\n  margin-bottom: 40px !important;\n}\n.map .map-wrapper {\n  position: relative;\n}\n.map .map-icons {\n  width: 6px;\n  height: 6px;\n  position: absolute;\n  background-color: #A4E7D4;\n  border-radius: 50%;\n  transform: translate(-55%, -55%);\n  animation: 1.4s ease-out -1.4s infinite alternate forwards map-glowing;\n}\n.map .map-icons.usa {\n  top: 45%;\n  left: 17.75%;\n}\n.map .map-icons.france {\n  top: 36%;\n  left: 48.65%;\n}\n.map .map-icons.columbia {\n  top: 34.9%;\n  left: 52.8%;\n}\n.map .map-icons.saudia {\n  top: 51.7%;\n  left: 58.6%;\n}\n.map .map-icons.pakistan {\n  top: 51.7%;\n  left: 68.2%;\n}\n.map .map-icons.sa {\n  top: 84.6%;\n  left: 52.8%;\n}\n.map .map-icons.aus {\n  top: 73.6%;\n  left: 88%;\n}\n.map .map-icons.japan {\n  top: 43.6%;\n  left: 88.4%;\n}\n@keyframes map-glowing {\n  0% {\n    box-shadow: 0px 0px 1px 0px #A4E7D488;\n  }\n  100% {\n    box-shadow: 0px 0px 1px 5px #A4E7D488;\n  }\n}\n",".technology-slider {\n  width: 100%;\n}\n.technology-slide {\n  padding: 45px 54px;\n  width: 200px;\n  height: 200px;\n  display: flex;\n  justify-content: center;\n  margin: auto;\n  @media (max-width: 991px) {\n    padding: 30px 50px;\n  }\n  @media (max-width: 767px) {\n    padding: 30px 35px;\n    width: 150px;\n    height: 150px;\n  }\n  border: 1px solid var(--stroke, #c8c8c8);\n  border-radius: 32px;\n}\n.technology-slide .technology-box {\n  gap: 24px;\n  width: fit-content;\n  @media (max-width: 767px) {\n    gap: 16px;\n  }\n}\n.technology-slide .technology-box p {\n  margin-bottom: 0px !important;\n  @media (max-width: 767px) {\n    font-size: 16px;\n  }\n}\n.technology-slide .technology-box img {\n  object-fit: contain;\n  @media (max-width: 767px) {\n    height: 50px;\n    width: 50px;\n  }\n}\n.slider-prev,\n.slider-next